class JSONLDataset(torch.utils.data.Dataset):
    """Torch dataset wrapper for a ProactiveBench JSONL file.

    The dataset eagerly loads all records.
    """

    def __init__(self, path: str, dataset: str):
        """Load records from ``path``."""
        super().__init__()
        self.data = []
        # Samples matching any configured key/value pair are excluded.
        self.skip_args = {"strong_occlusions": False}
        with jsonlines.open(path, "r") as jsonl_reader:
            for line in jsonl_reader:
                if self._check_skip_args(line) and line["id"] in FILTER[dataset]:
                    self.data.append(line)

    def __len__(self):
        """Return the number of retained samples."""
        return len(self.data)

    def __getitem__(self, index):
        """Return a single sample by index."""
        return self.data[index]

    def _check_skip_args(self, line):
        """Return ``True`` when a sample should be kept in the dataset."""
        if self.skip_args is None:
            return True

        for arg in self.skip_args:
            if arg in line and line[arg] == self.skip_args[arg]:
                return False
        return True


def load_proactivebench_dataset(data_dir: str, dataset: str):
    """Load the preprocessed ProactiveBench split from ``data_dir``."""
    path = os.path.join(data_dir, dataset + "_preprocessed.jsonl")
    dataset = JSONLDataset(path, dataset)
    return dataset


def apply_multi_choice_template(question: str, options: list, short_answer: bool = False):
    """Format a question and answer options into the prompt expected by the model."""
    user_prompt = question
    user_prompt += " Choose from the following options. Options:\n"
    user_prompt += "".join([f"{chr(65+i)}. {option}\n" for i, option in enumerate(options)])
    if short_answer:
        user_prompt += "Please only return one of the options without any other words."
    return user_prompt


def apply_conversation_template(user_prompt: str, image_path: str, transform: callable):
    """Build the conversation payload consumed by multimodal model backends."""
    conversation = [
        {
            "role": "user",
            "content": [
                {"type": "image", "image": f"file://{image_path}"},
                {"type": "transform", "transform": transform},
                {"type": "text", "text": user_prompt},
            ],
        }
    ]
    return conversation


def load_image(conversation: list, model_name: str):
    """Load and transform images from a conversation for the requested model.

    Qwen models use ``process_vision_info`` to extract image objects, while
    other backends load image files directly from the conversation payload.
    """
    if "Qwen" in model_name:
        image, _ = process_vision_info(conversation)
        transform = [
            content["transform"]
            for turn in conversation
            for content in turn["content"]
            if turn["role"] == "user" and content["type"] == "transform"
        ]

    else:
        image = []
        transform = []
        # Non-Qwen backends expect us to materialize image files ourselves.
        for turn in conversation:
            if turn["role"] == "user":
                for content in turn["content"]:
                    if content["type"] == "image":
                        image_path = content["image"]
                        image.append(Image.open(image_path.replace("file://", "")).convert("RGB"))
                    if content["type"] == "transform":
                        transform.append(content["transform"])

    image = [t(img) for img, t in zip(image, transform)]
    return image
